(204, NULL, 65, 0, 0, 0, 0, 1, 0, 22, 1, 'long eaton appliances', 'https://tc.tradetracker.net/?c=36638&m=12&a=496844&r=&u=%2F', 'uploads/1759869083.webp', NULL, NULL, NULL, NULL, NULL, NULL, 'Long Eaton Appliances is your trusted local supplier of quality kitchen appliances, including washing machines, ovens, fridge freezers, tumble dryers, and dishwashers. Based in Long Eaton, we provide expert advice, fast delivery, and professional installation across Nottingham, Derby, and surrounding areas. Whether you\'re upgrading your kitchen or replacing a faulty appliance, we stock top brands at competitive prices. Our friendly team is here to help you find the perfect appliance to suit your home and budget. Visit our showroom or browse online to discover great deals, reliable products, and excellent customer service from Long Eaton’s appliance specialists.\r\n\r\nLet me know if you want a version with specific keywords added or tailored for a particular platform (Google Business, homepage, etc.).', NULL, '<p><br></p>', NULL, 'long-eaton-appliances', NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 20:31:23', '2025-11-03 23:01:37'),
(205, NULL, 66, 0, 0, 0, 0, 1, 0, 23, 1, 'Komodo', 'https://tc.tradetracker.net/?c=25851&m=12&a=496844&r=&u=', 'uploads/1759869948.webp', NULL, NULL, NULL, NULL, 53, 53, 'Komodo is a leading ethical fashion brand, offering sustainable clothing made from organic cotton, bamboo, hemp, and eco-friendly materials. Since 1988, Komodo has pioneered environmentally conscious fashion, blending timeless design with sustainability. Our collections include stylish men’s and women’s wear, designed for comfort, durability, and a low carbon footprint. We partner with ethical factories and support fair wages, animal welfare, and slow fashion principles. Whether you\'re looking for eco-friendly outerwear, vegan shoes, or everyday basics, Komodo is your go-to sustainable clothing brand. Shop online for responsible fashion that looks good and feels even better—because style and ethics go hand in hand.', NULL, '<p><br></p>', NULL, 'komodo', NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 20:45:48', '2025-11-03 22:52:26'),
(206, NULL, 67, 0, 0, 0, 0, 1, 0, 32, 1, 'Lost Mary', NULL, 'uploads/1759871332.webp', NULL, NULL, NULL, NULL, 53, 53, 'Lost Mary is a leading brand in the disposable vape market, known for its sleek design, powerful performance, and wide range of bold, fruity flavours. Perfect for on-the-go vaping, Lost Mary vapes offer a smooth nicotine hit with advanced mesh coil technology for enhanced flavour and vapour production. Each device is pre-filled, rechargeable, and ready to use—no refilling or maintenance needed. Choose from best-selling Lost Mary flavours like Blue Razz Ice, Watermelon, and Pink Lemonade. Ideal for beginners and experienced vapers alike, Lost Mary delivers a satisfying and convenient vape experience. Explore the full range at top UK vape retailers.', NULL, '<p><br></p>', NULL, 'lost-mary', NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 21:08:52', '2025-11-03 22:10:17'),
